import React, { useEffect, useState } from 'react';
import { categoriesAPI, productsAPI } from '../../api';
import { useCart } from '../../context/CartContext';
import ProductDetailsModal from '../../components/ProductDetailsModal/ProductDetailsModal';
import styles from './CatalogPage.module.css';

export default function CatalogPage() {
  const { addItem } = useCart();

  const [categories, setCategories] = useState([]);
  const [products, setProducts] = useState([]);
  const [selectedCategory, setSelectedCategory] = useState('all');
  const [search, setSearch] = useState('');
  const [minPrice, setMinPrice] = useState('');
  const [maxPrice, setMaxPrice] = useState('');
  const [selectedProduct, setSelectedProduct] = useState(null);

  useEffect(() => {
    categoriesAPI.getAll().then(({ data }) => setCategories(data.categories || []));
  }, []);

  useEffect(() => {
    const load = async () => {
      const params = {
        page: 1,
        limit: 100,
      };

      if (selectedCategory !== 'all') params.categorySlug = selectedCategory;
      if (search) params.search = search;
      if (minPrice) params.minPrice = minPrice;
      if (maxPrice) params.maxPrice = maxPrice;

      const { data } = await productsAPI.getAll(params);
      setProducts(data.products || []);
    };

    load();
  }, [selectedCategory, search, minPrice, maxPrice]);

  return (
    <div className={styles.page}>
      <div className="container">
        <h1 className="section-title">Каталог</h1>
        <p className="section-subtitle">Список товаров с быстрым просмотром</p>

        <div className={styles.filters}>
          <input
            className={styles.input}
            placeholder="Поиск"
            value={search}
            onChange={(e) => setSearch(e.target.value)}
          />

          <div className={styles.chips}>
            <button
              className={`${styles.chip} ${selectedCategory === 'all' ? styles.active : ''}`}
              onClick={() => setSelectedCategory('all')}
            >
              Все
            </button>

            {categories.map((cat) => (
              <button
                key={cat.id}
                className={`${styles.chip} ${selectedCategory === cat.slug ? styles.active : ''}`}
                onClick={() => setSelectedCategory(cat.slug)}
              >
                {cat.name}
              </button>
            ))}
          </div>

          <div className={styles.priceRow}>
            <input
              className={styles.smallInput}
              placeholder="От"
              type="number"
              value={minPrice}
              onChange={(e) => setMinPrice(e.target.value)}
            />
            <input
              className={styles.smallInput}
              placeholder="До"
              type="number"
              value={maxPrice}
              onChange={(e) => setMaxPrice(e.target.value)}
            />
          </div>
        </div>

        <div className={styles.list}>
          {products.map((p) => (
            <button
              key={p.id}
              className={styles.row}
              onClick={() => setSelectedProduct(p)}
            >
              <img
                src={p.imageUrl || p.image_url || 'https://picsum.photos/seed/frukt-kray/240/160'}
                alt={p.name}
                className={styles.image}
              />

              <div className={styles.info}>
                <div className={styles.top}>
                  <h3 className={styles.name}>{p.name}</h3>
                  <span className={styles.category}>{p.category?.name}</span>
                </div>

                <p className={styles.description}>
                  {p.description}
                </p>
              </div>

              <div className={styles.right}>
                <div className={styles.price}>{p.price.toLocaleString('ru-RU')} ₽</div>
                <div className={styles.actions}>
                  <span className={styles.more}>Открыть →</span>
                </div>
              </div>
            </button>
          ))}
        </div>
      </div>

      <ProductDetailsModal
        product={selectedProduct}
        onClose={() => setSelectedProduct(null)}
      />
    </div>
  );
}
